const listFailedScannerEntitiesByLibrary = `-- name: ListFailedScannerEntitiesByLibrary :many
SELECT id, library_id, media_type, scope_key, scope_paths, identity_key, title, year, provider_id, status, search_scan_run_id, fetch_scan_run_id, search_artifact_id, metadata_artifact_id, apply_artifact_id, error_message, data, discovered_at, searched_at, fetched_at, applied_at, updated_at, analysis_artifact_id, pipeline_generation FROM scanner_entities
WHERE library_id = $1
  AND error_message <> ''
  AND status IN ('metadata_error', 'apply_error', 'error', 'failed')
ORDER BY updated_at DESC, id DESC
`

// Pipeline failures happen after a search run has already been persisted, so
// scan_runs alone cannot describe the final outcome. Keep this query scoped to
// terminal error states; transient matched/fetching rows and review decisions
// are represented elsewhere in the scanner view.
func (q *Queries) ListFailedScannerEntitiesByLibrary(ctx context.Context, libraryID int64) ([]ScannerEntity, error) {
	rows, err := q.db.Query(ctx, listFailedScannerEntitiesByLibrary, libraryID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []ScannerEntity{}
	for rows.Next() {
		var i ScannerEntity
		if err := rows.Scan(
			&i.ID,
			&i.LibraryID,
			&i.MediaType,
			&i.ScopeKey,
			&i.ScopePaths,
			&i.IdentityKey,
			&i.Title,
			&i.Year,
			&i.ProviderID,
			&i.Status,
			&i.SearchScanRunID,
			&i.FetchScanRunID,
			&i.SearchArtifactID,
			&i.MetadataArtifactID,
			&i.ApplyArtifactID,
			&i.ErrorMessage,
			&i.Data,
			&i.DiscoveredAt,
			&i.SearchedAt,
			&i.FetchedAt,
			&i.AppliedAt,
			&i.UpdatedAt,
			&i.AnalysisArtifactID,
			&i.PipelineGeneration,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

